 1→import { NextResponse } from "next/server";
 2→import { requireStudent } from "@/lib/auth";
 3→import { prisma } from "@compass/db";
 4→import { Client } from "@upstash/qstash";
 5→
 6→export const maxDuration = 30;
 7→
 8→function getQStash() {
 9→  return new Client({ token: process.env.QSTASH_TOKEN! });
10→}
11→
12→export async function POST(
13→  _req: Request,
14→  { params }: { params: Promise<{ id: string }> }
15→) {
16→  try {
17→    const student = await requireStudent();
18→    const { id } = await params;
19→
20→    const session = await prisma.reflectionSession.findFirst({
21→      where: { id, studentId: student.id },
22→    });
23→
24→    if (!session) {
25→      return NextResponse.json({ error: "Not found" }, { status: 404 });
26→    }
27→
28→    if (session.completedAt) {
29→      return NextResponse.json({ error: "Session already submitted" }, { status: 400 });
30→    }
31→
32→    // Mark session as complete
33→    const now = new Date();
34→    const durationSeconds = Math.floor(
35→      (now.getTime() - session.createdAt.getTime()) / 1000
36→    );
37→
38→    await prisma.reflectionSession.update({
39→      where: { id },
40→      data: {
41→        completedAt: now,
42→        durationSeconds,
43→      },
44→    });
45→
46→    // Enqueue synthesis job via QStash
47→    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? "http://localhost:3000";
48→    await getQStash().publishJSON({
49→      url: `${appUrl}/api/webhooks/qstash`,
50→      body: {
51→        type: "POST_SESSION_SYNTHESIS",
52→        data: {
53→          studentId: student.id,
54→          sessionId: id,
55→        },
56→        triggeredAt: now.toISOString(),
57→      },
58→      // 30 second delay to let any last writes settle
59→      delay: 30,
60→    });
61→
62→    return NextResponse.json({ success: true, completedAt: now });
63→  } catch (error) {
64→    const message = error instanceof Error ? error.message : "Unknown error";
65→    return NextResponse.json({ error: message }, { status: 400 });
66→  }
67→}
